@@ -80,92 +80,133 @@ describe('useLinksListing', () => {
     });

     it('fetches children all pages with the same sorting', async () => {
         mockRequst.mockReturnValueOnce({ Links: linksToApiLinks(LINKS.slice(0, PAGE_SIZE)) });
         mockRequst.mockReturnValueOnce({ Links: linksToApiLinks(LINKS.slice(PAGE_SIZE)) });
         await act(async () => {
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId', {
                 sortField: 'createTime',
                 sortOrder: SORT_DIRECTION.ASC,
             });
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId', {
                 sortField: 'createTime',
                 sortOrder: SORT_DIRECTION.ASC,
             });
         });
         // Check fetch calls - two pages.
         expect(mockRequst.mock.calls.map(([{ params }]) => params)).toMatchObject([
             { Page: 0, Sort: 'CreateTime', Desc: 0 },
             { Page: 1, Sort: 'CreateTime', Desc: 0 },
         ]);
-        expect(hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId')).toMatchObject([LINKS, false]);
+        const result1 = hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId');
+        expect(result1).toHaveProperty('cachedLinks');
+        expect(result1).toHaveProperty('isDecrypting');
+        expect(result1.cachedLinks).toMatchObject(LINKS);
+        expect(result1.isDecrypting).toBe(false);
+        expect(Object.keys(result1)).toEqual(['cachedLinks', 'isDecrypting']);
         // Check decrypt calls - all links were decrypted.
         expect(mockDecrypt.mock.calls.map(([, , { linkId }]) => linkId)).toMatchObject(
             LINKS.map(({ linkId }) => linkId)
         );
     });

     it('fetches from the beginning when sorting changes', async () => {
         const links = LINKS.slice(0, PAGE_SIZE);
         mockRequst.mockReturnValue({ Links: linksToApiLinks(links) });
         await act(async () => {
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId', {
                 sortField: 'createTime',
                 sortOrder: SORT_DIRECTION.ASC,
             });
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId', {
                 sortField: 'createTime',
                 sortOrder: SORT_DIRECTION.DESC,
             });
         });
         // Check fetch calls - twice starting from the first page.
         expect(mockRequst.mock.calls.map(([{ params }]) => params)).toMatchObject([
             { Page: 0, Sort: 'CreateTime', Desc: 0 },
             { Page: 0, Sort: 'CreateTime', Desc: 1 },
         ]);
-        expect(hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId')).toMatchObject([links, false]);
+        const result2 = hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId');
+        expect(result2).toHaveProperty('cachedLinks');
+        expect(result2).toHaveProperty('isDecrypting');
+        expect(result2.cachedLinks).toMatchObject(links);
+        expect(result2.isDecrypting).toBe(false);
         // Check decrypt calls - the second call returned the same links, no need to decrypt them twice.
         expect(mockDecrypt.mock.calls.map(([, , { linkId }]) => linkId)).toMatchObject(
             links.map(({ linkId }) => linkId)
         );
     });

     it('skips fetch if all was fetched', async () => {
         const links = LINKS.slice(0, 5);
         mockRequst.mockReturnValue({ Links: linksToApiLinks(links) });
         await act(async () => {
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId');
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId');
         });
         // Check fetch calls - first call fetched all, no need to call the second.
         expect(mockRequst).toBeCalledTimes(1);
-        expect(hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId')).toMatchObject([links, false]);
+        const result3 = hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId');
+        expect(result3.cachedLinks).toMatchObject(links);
+        expect(result3.isDecrypting).toBe(false);
     });

     it('loads the whole folder', async () => {
         mockRequst.mockReturnValueOnce({ Links: linksToApiLinks(LINKS.slice(0, PAGE_SIZE)) });
         mockRequst.mockReturnValueOnce({ Links: linksToApiLinks(LINKS.slice(PAGE_SIZE)) });
         await act(async () => {
             await hook.current.loadChildren(abortSignal, 'shareId', 'parentLinkId');
         });
         expect(mockRequst.mock.calls.map(([{ params }]) => params)).toMatchObject([
             { Page: 0, Sort: 'CreateTime', Desc: 0 },
             { Page: 1, Sort: 'CreateTime', Desc: 0 },
         ]);
     });

     it('continues the load of the whole folder where it ended', async () => {
         mockRequst.mockReturnValueOnce({ Links: linksToApiLinks(LINKS.slice(0, PAGE_SIZE)) });
         mockRequst.mockReturnValueOnce({ Links: linksToApiLinks(LINKS.slice(PAGE_SIZE)) });
         await act(async () => {
             await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId', {
                 sortField: 'metaDataModifyTime', // Make sure it is not default.
                 sortOrder: SORT_DIRECTION.ASC,
             });
             await hook.current.loadChildren(abortSignal, 'shareId', 'parentLinkId');
         });
         expect(mockRequst.mock.calls.map(([{ params }]) => params)).toMatchObject([
             { Page: 0, Sort: 'ModifyTime', Desc: 0 }, // Done by fetchChildrenNextPage.
             { Page: 1, Sort: 'ModifyTime', Desc: 0 }, // Done by loadChildren, continues with the same sorting.
         ]);
     });
+
+    it('returns entity copies not sharing store references', async () => {
+        const links = LINKS.slice(0, 5);
+        mockRequst.mockReturnValue({ Links: linksToApiLinks(links) });
+        await act(async () => {
+            await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId');
+        });
+
+        const result1 = hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId');
+        const result2 = hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId');
+
+        expect(result1.cachedLinks).toHaveLength(links.length);
+        expect(result1.cachedLinks[0]).toEqual(result2.cachedLinks[0]);
+        expect(result1.cachedLinks[0]).not.toBe(result2.cachedLinks[0]);
+    });
+
+    it('returns a frozen immutable result object', async () => {
+        const links = LINKS.slice(0, 5);
+        mockRequst.mockReturnValue({ Links: linksToApiLinks(links) });
+        await act(async () => {
+            await hook.current.fetchChildrenNextPage(abortSignal, 'shareId', 'parentLinkId');
+        });
+
+        const result = hook.current.getCachedChildren(abortSignal, 'shareId', 'parentLinkId');
+
+        expect(result).toHaveProperty('cachedLinks');
+        expect(Array.isArray(result.cachedLinks)).toBe(true);
+        expect(result.cachedLinks.length).toBeGreaterThan(0);
+        expect(Object.isFrozen(result)).toBe(true);
+    });
 });
